{
  "grammar": [
    {
      "pattern": "從 + time/event + 到 + time/event + (一直) + V",
      "structure": ["從", "time/event", "到", "time/event", "一直", "V"],
      "explanation_en": "Use this pattern to describe an action or state that lasts from a starting point to an ending point. It emphasizes the duration or continuity.",
      "title": "從...到... (From... to...)",
      "meaning": "Indicates a duration from start to end.",
      "when_to_use": ["When describing how long a problem lasted", "When explaining the timeline of an event"],
      "when_not_to_use": ["When the action is completed at a single point", "When no clear start or end is given"],
      "pragmatic_notes": "In Taiwan, this pattern is very common in daily conversation, especially when explaining problems like '從昨天到今天一直漏水' (leaking from yesterday to today).",
      "word_order_notes": "The time/event phrases must follow 從 and 到 respectively. 一直 is optional but adds emphasis.",
      "english_contrast": "English uses 'from...to...' similarly, but Chinese often adds 一直 for continuity.",
      "korean_contrast": "Korean uses '~부터 ~까지' similarly, but Chinese word order is more fixed.",
      "negative_examples": [
        {
          "text": "從昨天到今天漏水。",
          "error": "Missing 一直 to emphasize the continuous state of leaking."
        }
      ],
      "incorrect_examples": [
        {
          "text": "從昨天到今天漏水。",
          "error": "Missing 一直 to emphasize the continuous state of leaking."
        }
      ],
      "transformation_drills": ["Change '從早上到晚上一直工作' to '從早上到晚上一直休息'"],
      "production_drills": ["Describe a problem that lasted from yesterday to today."],
      "common_error_patterns": ["Forgetting 一直 when emphasizing continuity", "Misplacing 從 and 到"],
      "repair_feedback": {
        "word_order": "Make sure 從 comes before the start time and 到 before the end time.",
        "politeness": "This pattern is neutral; no special politeness needed.",
        "vocabulary": "Use time words like 昨天, 今天, 早上, 晚上."
      }
    },
    {
      "pattern": "Subject + 需要 + V + Object",
      "structure": ["Subject", "需要", "V", "Object"],
      "explanation_en": "Use this pattern to express a need or requirement for an action. It is commonly used in service or repair contexts.",
      "title": "需要 + V (Need to do something)",
      "meaning": "Expresses necessity or requirement.",
      "when_to_use": ["When requesting a repair or service", "When explaining what needs to be done"],
      "when_not_to_use": ["When expressing a desire (use 想 instead)", "When the action is already completed"],
      "pragmatic_notes": "In Taiwan, this is polite and direct. For example, '我需要修理水龍頭' (I need to fix the faucet) is common in housing contexts.",
      "word_order_notes": "需要 is followed directly by a verb, then the object. No 的 needed.",
      "english_contrast": "English uses 'need to + verb', similar structure.",
      "korean_contrast": "Korean uses '~을/를 필요하다' but word order differs (object before verb).",
      "negative_examples": [
        {
          "text": "我需要修理的水龍頭。",
          "error": "Adding 的 makes it 'the faucet that needs repair', not 'need to repair the faucet'."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我需要修理的水龍頭。",
          "error": "Adding 的 makes it 'the faucet that needs repair', not 'need to repair the faucet'."
        }
      ],
      "transformation_drills": ["Change '我需要看醫生' to '我需要吃藥'"],
      "production_drills": ["Say what you need to do for a health problem."],
      "common_error_patterns": ["Adding 的 between 需要 and the verb", "Using 想 instead of 需要 for necessity"],
      "repair_feedback": {
        "word_order": "Place 需要 before the verb, no 的.",
        "politeness": "This is neutral; for polite requests, add 請 or 不好意思.",
        "vocabulary": "Use verbs like 修理, 檢查, 看醫生, 吃藥."
      }
    },
    {
      "pattern": "Subject + 已經 + V + 了",
      "structure": ["Subject", "已經", "V", "了"],
      "explanation_en": "Use this pattern to indicate that an action has already been completed. It is often used to report progress or resolution.",
      "title": "已經...了 (Already...)",
      "meaning": "Indicates completion of an action.",
      "when_to_use": ["When reporting that a problem has been resolved", "When confirming that something has been done"],
      "when_not_to_use": ["When the action is ongoing (use 正在 instead)", "When the action hasn't started yet"],
      "pragmatic_notes": "In Taiwan, this is common in service contexts, e.g., '師傅已經修理好了' (The repairman has already fixed it).",
      "word_order_notes": "已經 comes before the verb, and 了 is placed at the end of the sentence.",
      "english_contrast": "English uses 'already + past tense', similar meaning.",
      "korean_contrast": "Korean uses '이미 ~했다', but word order is different (already at beginning).",
      "negative_examples": [
        {
          "text": "已經我修理了。",
          "error": "已經 must come before the verb, not the subject."
        }
      ],
      "incorrect_examples": [
        {
          "text": "已經我修理了。",
          "error": "已經 must come before the verb, not the subject."
        }
      ],
      "transformation_drills": ["Change '我已經掛號了' to '我已經看醫生了'"],
      "production_drills": ["Report that you have already made an appointment."],
      "common_error_patterns": ["Placing 已經 before the subject", "Forgetting 了 at the end"],
      "repair_feedback": {
        "word_order": "Place 已經 before the verb, and 了 at the end.",
        "politeness": "This is neutral; for polite confirmation, add 已經...了.",
        "vocabulary": "Use verbs like 修理, 掛號, 檢查, 取消."
      }
    }
  ]
}
